// Avtomatik dəyər təyini ilə rəqəmli enum
enum Direction {
  Up,
  Down,
  Left,
  Right
}

let move: Direction = Direction.Up;
console.log(move); // 0
console.log(Direction[0]); // Up
move = Direction.Down;
console.log(move); // 1
// move = 5; // Xəta: 5 Direction tipinə uyğun deyil

// Xüsusi dəyər təyini ilə rəqəmli enum
enum Status {
  Active = 1,
  Inactive = 2,
  Pending = 4
}

let userStatus: Status = Status.Active;
console.log(userStatus); // 1
console.log(Status[userStatus]); // Active
userStatus = Status.Pending;
console.log(userStatus); // 4
// userStatus = 3; // Xəta: 3 Status tipinə uyğun deyil

// Rəqəmli enumlar ilə tip aliaslarının müqayisəsi
enum Priority {
  Low = 1,
  Medium = 2,
  High = 3
}

type PriorityAlias = 1 | 2 | 3;

let enumPriority: Priority = Priority.Low;
let aliasPriority: PriorityAlias = 1;

console.log(enumPriority); // 1
console.log(Priority[enumPriority]); // Low
console.log(aliasPriority); // 1
// enumPriority = 4; // Xəta: 4 Priority tipinə uyğun deyil
// aliasPriority = 4; // Xəta: 4 PriorityAlias tipinə uyğun deyil

// Tərs axtarış ilə rəqəmli enum
enum Day {
  Monday = 1,
  Tuesday = 2,
  Wednesday = 3
}

let today: Day = Day.Monday;
console.log(today); // 1
console.log(Day[today]); // Monday
console.log(Day[2]); // Tuesday
// today = 4; // Xəta: 4 Day tipinə uyğun deyil

// Funksiyalarda rəqəmli enumlar
enum StatusCode {
  Success = 200,
  NotFound = 404,
  Error = 500
}

function getStatusMessage(code: StatusCode): string {
  return `Status code: ${code}`;
}

let response: StatusCode = StatusCode.Success;
console.log(getStatusMessage(response)); // Status code: 200
response = StatusCode.Error;
console.log(getStatusMessage(response)); // Status code: 500
// response = 403; // Xəta: 403 StatusCode tipinə uyğun deyil

// Praktik nümunə
enum OrderPriority {
  Low = 1,
  Medium = 2,
  High = 3
}

function displayPriority(priority: OrderPriority): string {
  return `Order priority: ${priority} (${OrderPriority[priority]})`;
}

let order: OrderPriority = OrderPriority.Low;
console.log(displayPriority(order)); // Order priority: 1 (Low)
order = OrderPriority.High;
console.log(displayPriority(order)); // Order priority: 3 (High)
// order = 4; // Xəta: 4 OrderPriority tipinə uyğun deyil

// Təhlükəsizlik nümunəsi
enum Level {
  Beginner = 1,
  Intermediate = 2,
  Advanced = 3
}

function getLevelDescription(level: Level): string {
  return `Level: ${level} (${Level[level]})`;
}

let userLevel: Level = Level.Beginner;
console.log(getLevelDescription(userLevel)); // Level: 1 (Beginner)
// userLevel = 4; // Xəta: 4 Level tipinə uyğun deyil

// Səhvə yol açan nümunə
let unsafe: any = 1;
console.log(unsafe); // 1, lakin tip təhlükəsizliyi yoxdur
unsafe = 5; // Keçərlidir, lakin təhlükəsiz deyil

// Düzgün yol
enum Status {
  Online = 1,
  Offline = 2
}

let safeStatus: Status = Status.Online;
console.log(safeStatus); // 1
// safeStatus = 3; // Xəta: 3 Status tipinə uyğun deyil

// Real layihə ssenarisi
enum HttpStatus {
  OK = 200,
  BadRequest = 400,
  NotFound = 404,
  InternalError = 500
}

function processResponse(status: HttpStatus): string {
  return `Response status: ${status} (${HttpStatus[status]})`;
}

let response: HttpStatus = HttpStatus.OK;
console.log(processResponse(response)); // Response status: 200 (OK)
response = HttpStatus.NotFound;
console.log(processResponse(response)); // Response status: 404 (NotFound)
// response = 403; // Xəta: 403 HttpStatus tipinə uyğun deyil

