enum Priority {
  Low = 1,
  Medium = 2,
  High = 3
}

type PriorityAlias = 1 | 2 | 3;

let enumPriority: Priority = Priority.Low;
let aliasPriority: PriorityAlias = 1;

console.log(enumPriority); // 1
console.log(Priority[enumPriority]); // Low
console.log(aliasPriority); // 1
// enumPriority = 4; // Error: 4 is not assignable to Priority
// aliasPriority = 4; // Error: 4 is not assignable to PriorityAlias

// Reverse mapping with numeric enum
enum Day {
  Monday = 1,
  Tuesday = 2,
  Wednesday = 3
}

let today: Day = Day.Monday;
console.log(today); // 1
console.log(Day[today]); // Monday
console.log(Day[2]); // Tuesday
// today = 4; // Error: 4 is not assignable to Day

